/**
 * Minimal Markdown parser fallback.
 * Provides a subset of the marked.js API used by the app.
 * If the full marked library is available, prefer loading it instead.
 */
(function (root) {
  'use strict';

  function escapeHtml(text) {
    return text
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function parseInline(text) {
    // Code spans (backticks) - process first to avoid conflicts
    text = text.replace(/`([^`]+)`/g, '<code>$1</code>');
    // Images ![alt](url)
    text = text.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img alt="$1" src="$2" />');
    // Links [text](url)
    text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>');
    // Bold + italic ***text***
    text = text.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
    // Bold **text** or __text__
    text = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    text = text.replace(/__(.+?)__/g, '<strong>$1</strong>');
    // Italic *text* or _text_
    text = text.replace(/\*(.+?)\*/g, '<em>$1</em>');
    text = text.replace(/_(.+?)_/g, '<em>$1</em>');
    // Strikethrough ~~text~~
    text = text.replace(/~~(.+?)~~/g, '<del>$1</del>');
    return text;
  }

  function parse(markdown) {
    if (typeof markdown !== 'string') return '';

    var lines = markdown.split('\n');
    var html = [];
    var i = 0;
    var inCodeBlock = false;
    var codeLang = '';
    var codeLines = [];
    var inList = false;
    var listType = '';
    var inBlockquote = false;
    var blockquoteLines = [];
    var inTable = false;
    var tableRows = [];
    var tableAligns = [];

    function flushBlockquote() {
      if (inBlockquote && blockquoteLines.length > 0) {
        html.push('<blockquote>' + parse(blockquoteLines.join('\n')) + '</blockquote>');
        blockquoteLines = [];
        inBlockquote = false;
      }
    }

    function flushList() {
      if (inList) {
        html.push(listType === 'ol' ? '</ol>' : '</ul>');
        inList = false;
        listType = '';
      }
    }

    function flushTable() {
      if (inTable && tableRows.length > 0) {
        var out = '<table>';
        for (var r = 0; r < tableRows.length; r++) {
          if (r === 0) {
            out += '<thead><tr>';
            tableRows[r].forEach(function (cell, ci) {
              var align = tableAligns[ci] ? ' style="text-align:' + tableAligns[ci] + '"' : '';
              out += '<th' + align + '>' + parseInline(cell.trim()) + '</th>';
            });
            out += '</tr></thead><tbody>';
          } else {
            out += '<tr>';
            tableRows[r].forEach(function (cell, ci) {
              var align = tableAligns[ci] ? ' style="text-align:' + tableAligns[ci] + '"' : '';
              out += '<td' + align + '>' + parseInline(cell.trim()) + '</td>';
            });
            out += '</tr>';
          }
        }
        out += '</tbody></table>';
        html.push(out);
        tableRows = [];
        tableAligns = [];
        inTable = false;
      }
    }

    while (i < lines.length) {
      var line = lines[i];

      // Fenced code blocks
      if (/^```/.test(line)) {
        if (!inCodeBlock) {
          flushBlockquote();
          flushList();
          flushTable();
          inCodeBlock = true;
          codeLang = line.replace(/^```\s*/, '').trim();
          codeLines = [];
          i++;
          continue;
        } else {
          var langClass = codeLang ? ' class="language-' + escapeHtml(codeLang) + '"' : '';
          html.push('<pre><code' + langClass + '>' + escapeHtml(codeLines.join('\n')) + '</code></pre>');
          inCodeBlock = false;
          codeLang = '';
          codeLines = [];
          i++;
          continue;
        }
      }

      if (inCodeBlock) {
        codeLines.push(line);
        i++;
        continue;
      }

      // Blank line
      if (/^\s*$/.test(line)) {
        flushBlockquote();
        flushList();
        flushTable();
        i++;
        continue;
      }

      // Blockquote
      if (/^>\s?/.test(line)) {
        flushList();
        flushTable();
        inBlockquote = true;
        blockquoteLines.push(line.replace(/^>\s?/, ''));
        i++;
        continue;
      } else if (inBlockquote) {
        flushBlockquote();
      }

      // Table detection: line with pipes and next line is separator
      if (!inTable && line.indexOf('|') !== -1 && i + 1 < lines.length && /^\|?[\s:]*-{2,}[\s:]*(\|[\s:]*-{2,}[\s:]*)*\|?\s*$/.test(lines[i + 1])) {
        flushList();
        inTable = true;
        var headerCells = line.replace(/^\||\|$/g, '').split('|');
        tableRows.push(headerCells);
        // Parse alignment row
        var sepCells = lines[i + 1].replace(/^\||\|$/g, '').split('|');
        tableAligns = sepCells.map(function (s) {
          s = s.trim();
          if (/^:-+:$/.test(s)) return 'center';
          if (/^-+:$/.test(s)) return 'right';
          if (/^:-+$/.test(s)) return 'left';
          return '';
        });
        i += 2;
        continue;
      }

      if (inTable) {
        if (line.indexOf('|') !== -1) {
          var cells = line.replace(/^\||\|$/g, '').split('|');
          tableRows.push(cells);
          i++;
          continue;
        } else {
          flushTable();
        }
      }

      // Headings
      var headingMatch = line.match(/^(#{1,6})\s+(.+)$/);
      if (headingMatch) {
        flushList();
        var level = headingMatch[1].length;
        var text = parseInline(headingMatch[2].replace(/\s+#+\s*$/, ''));
        html.push('<h' + level + '>' + text + '</h' + level + '>');
        i++;
        continue;
      }

      // Horizontal rule
      if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line.trim())) {
        flushList();
        html.push('<hr />');
        i++;
        continue;
      }

      // Unordered list
      var ulMatch = line.match(/^(\s*)[*+-]\s+(.+)$/);
      if (ulMatch) {
        flushTable();
        if (!inList || listType !== 'ul') {
          flushList();
          inList = true;
          listType = 'ul';
          html.push('<ul>');
        }
        html.push('<li>' + parseInline(ulMatch[2]) + '</li>');
        i++;
        continue;
      }

      // Ordered list
      var olMatch = line.match(/^(\s*)\d+[.)]\s+(.+)$/);
      if (olMatch) {
        flushTable();
        if (!inList || listType !== 'ol') {
          flushList();
          inList = true;
          listType = 'ol';
          html.push('<ol>');
        }
        html.push('<li>' + parseInline(olMatch[2]) + '</li>');
        i++;
        continue;
      }

      // Regular paragraph
      flushList();
      flushTable();
      html.push('<p>' + parseInline(line) + '</p>');
      i++;
    }

    // Flush remaining state
    if (inCodeBlock) {
      html.push('<pre><code>' + escapeHtml(codeLines.join('\n')) + '</code></pre>');
    }
    flushBlockquote();
    flushList();
    flushTable();

    return html.join('\n');
  }

  var marked = {
    parse: parse,
    parseInline: parseInline,
    setOptions: function () { return marked; },
    use: function () { return marked; }
  };

  // Export for CJS and browser global
  if (typeof module !== 'undefined' && module.exports) {
    module.exports = { marked: marked };
  }
  if (typeof root !== 'undefined') {
    root.marked = marked;
  }
})(typeof globalThis !== 'undefined' ? globalThis : typeof window !== 'undefined' ? window : typeof self !== 'undefined' ? self : this);
